VALUES
  ('locality-d0d1b9a2-moex-00004', 'locality-d0d1b9a2', 'locality-d0d1b9a2-moex-114-78566e18', 'sub-locality-d0d1b9a2-01', NULL, 'single_choice', '甲公司於X1年初出租推土機予乙公司，約定每年底收取租金$300,000，租期5年，估計租期屆 滿日該機器殘值為$150,000，乙公司保證其中$50,000。該推土機於X1年初租賃開始日時，在甲 公司的帳面金額等於公允價值$1,160,000，甲公司隱含利率為12%。若此租賃對於甲公司為直接 型融資租賃，則甲公司因此項租賃而支付的原始直接成本為何？（5期，利率12%，複利現值因 子=0.56743，普通年金現值因子=3.60478）', '["$6,549", "$113,158", "$120,784", "$483,451"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:05+00:00", "source_pdf_sha1": "58d279cd0639", "answer_pdf_sha1": "c8f8c4a54c39", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "313", "s": "1207", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "會計"}'::jsonb, NULL),
  ('locality-d0d1b9a2-moex-00005', 'locality-d0d1b9a2', 'locality-d0d1b9a2-moex-114-78566e18', 'sub-locality-d0d1b9a2-01', NULL, 'single_choice', '甲公司於X1年1月1日向乙銀行借款$100,000，分5年清償，每年12月31日支付$26,380，有 效利率為10%。若甲公司採曆年制，則甲公司X1年12月31日資產負債表應列示為流動負債之 金額為何？', '["$16,380", "$18,018", "$26,380", "$83,620"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:05+00:00", "source_pdf_sha1": "58d279cd0639", "answer_pdf_sha1": "c8f8c4a54c39", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "313", "s": "1207", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "會計"}'::jsonb, NULL),
  ('locality-d0d1b9a2-moex-00006', 'locality-d0d1b9a2', 'locality-d0d1b9a2-moex-114-78566e18', 'sub-locality-d0d1b9a2-01', NULL, 'single_choice', '甲公司於X1年初成立，該年度之稅前會計淨利為$1,000,000，稅率20%。甲公司並有下列事項：', '["公司發行美金計價之金融負債，年底評價時因匯率變動產生外幣兌換利益$300,000", "公司投資之政府公債，於當年度之免稅利息收入為$100,000", "公司X1年底對於應收帳款提列預期信用損失$100,000，也認列估計產品保固負債準備$400,000 有關甲公司X1年底之所得稅相關分錄，下列敘述何者正確？", "借記所得稅費用$180,000"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:05+00:00", "source_pdf_sha1": "58d279cd0639", "answer_pdf_sha1": "c8f8c4a54c39", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "313", "s": "1207", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "會計"}'::jsonb, NULL),
  ('locality-d0d1b9a2-moex-00007', 'locality-d0d1b9a2', 'locality-d0d1b9a2-moex-114-78566e18', 'sub-locality-d0d1b9a2-01', NULL, 'single_choice', '甲、乙兩家公司於X1年初以相同價格，各分別購入丙公司發行之債券面額$1,000,000，票面利率 5%，原始有效利率為4%。甲公司將此投資分類為透過其他綜合損益按公允價值衡量之投資，乙 公司則將此債券分類為按攤銷後成本衡量之投資。X1及X2年底，該債券之公允價值持續上升。 於X3年底，甲、乙兩公司又以相同價格，處分前述對丙公司之債券投資。下列敘述何者正確？', '["於X3年度甲公司認列之債券投資處分損益將大於乙公司", "於X3年度甲公司認列之債券投資利息收入將小於乙公司", "於X3年度甲公司攤銷之債券投資折溢價將大於乙公司", "於X3年度甲公司源自此債券投資交易對淨利之影響數將等於乙公司"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:05+00:00", "source_pdf_sha1": "58d279cd0639", "answer_pdf_sha1": "c8f8c4a54c39", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "313", "s": "1207", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "會計"}'::jsonb, NULL),
  ('locality-d0d1b9a2-moex-00008', 'locality-d0d1b9a2', 'locality-d0d1b9a2-moex-114-78566e18', 'sub-locality-d0d1b9a2-01', NULL, 'single_choice', '甲公司於X1年1月1日以$600,000取得乙公司普通股20%，採權益法會計處理。X1年7月1日， 甲公司再以$300,000購得乙公司10%普通股。乙公司X1年的全年淨利$150,000，係於X1年中 平均實現，且乙公司於X1年5月1日發放現金股利$30,000。試問甲公司於X1年12月31日投 資乙公司的帳面金額為何？', '["$939,000", "$931,500", "$991,500", "$999,000"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:05+00:00", "source_pdf_sha1": "58d279cd0639", "answer_pdf_sha1": "c8f8c4a54c39", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "313", "s": "1207", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "會計"}'::jsonb, NULL),
  ('locality-d0d1b9a2-moex-00009', 'locality-d0d1b9a2', 'locality-d0d1b9a2-moex-114-78566e18', 'sub-locality-d0d1b9a2-01', NULL, 'single_choice', '甲公司於X1年初成立時，訂定確定福利退休計畫。X1年及X2年當期服務成本分別為$400,000 與$440,000，該公司於X1年及X2年底分別提撥退休金$320,000與$360,000。若計畫資產實際報 酬率為12%，折現率為8%，則下列選項，何者屬於甲公司X2年底有關退休計畫的分錄？', '["借記：退休金費用$433,600", "貸記：現金$37,800", "借記：淨確定福利負債$153,600", "貸記：其他綜合損益—確定福利計畫再衡量數$12,800"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:05+00:00", "source_pdf_sha1": "58d279cd0639", "answer_pdf_sha1": "c8f8c4a54c39", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "313", "s": "1207", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "會計"}'::jsonb, NULL),
  ('locality-d0d1b9a2-moex-00010', 'locality-d0d1b9a2', 'locality-d0d1b9a2-moex-114-78566e18', 'sub-locality-d0d1b9a2-01', NULL, 'single_choice', '下列何者之會計處理應依照 IAS 41「農業」之規定？①農場為收成水蜜桃而種植之水蜜桃樹', '["漁撈公司漁船出海所捕獲之南極蝦", "僅", "應依IAS41", "僅"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:05+00:00", "source_pdf_sha1": "58d279cd0639", "answer_pdf_sha1": "c8f8c4a54c39", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "313", "s": "1207", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "會計"}'::jsonb, NULL),
  ('locality-d0d1b9a2-moex-00011', 'locality-d0d1b9a2', 'locality-d0d1b9a2-moex-114-78566e18', 'sub-locality-d0d1b9a2-01', NULL, 'single_choice', '有關無形資產之會計處理，下列何者正確？', '["非確定耐用年限之無形資產不論是否具有減損跡象都要定期進行減損測試，且減損損失不得迴轉", "於發展階段且達技術可行之無形資產不得攤銷，且不論是否具有減損跡象都要定期進行減損測試", "商譽應取得外部獨立之鑑價報告進行減損測試以符合可驗證性，且減損損失不得迴轉", "研究階段所投入之支出，原則上須立即認列為費用，僅於符合IAS38第57段之所有條件時， 始得認列為無形資產"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:05+00:00", "source_pdf_sha1": "58d279cd0639", "answer_pdf_sha1": "c8f8c4a54c39", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "313", "s": "1207", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "會計"}'::jsonb, NULL),
  ('locality-d0d1b9a2-moex-00012', 'locality-d0d1b9a2', 'locality-d0d1b9a2-moex-114-78566e18', 'sub-locality-d0d1b9a2-01', NULL, 'single_choice', '公司發行之下列非累積特別股，何者具有負債組成部分？①可買回（callable）特別股  ②可轉換 固定普通股數（不具重設價格條件）之特別股', '["僅", "具有負債組成部分", "僅", "具有負債組成部分"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:05+00:00", "source_pdf_sha1": "58d279cd0639", "answer_pdf_sha1": "c8f8c4a54c39", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "313", "s": "1207", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "會計"}'::jsonb, NULL),
